                project_id: params.0.project_id,
                limit: params.0.limit,
            };
            logic::code::search_code(&self.state, search_params)
                .await
                .map_err(to_rpc_error)
        } else {
            logic::code::recall_code(&self.state, params.0)
                .await
                .map_err(to_rpc_error)
        }
