pub fn rrf_merge(
    vector_results: &[(String, f32)],
    bm25_results: &[(String, f32)],
    ppr_results: &[(String, f32)],
    vector_weight: f32,
    bm25_weight: f32,
    ppr_weight: f32,
    limit: usize,
) -> Vec<(String, RrfScores)> {
    let mut scores: HashMap<String, RrfScores> = HashMap::new();

    for (rank, (id, original_score)) in vector_results.iter().enumerate() {
        let rrf_score = vector_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.vector_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in bm25_results.iter().enumerate() {
        let rrf_score = bm25_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.bm25_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in ppr_results.iter().enumerate() {
        let rrf_score = ppr_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.ppr_score = *original_score;
        entry.combined_score += rrf_score;
    }

    let mut results: Vec<_> = scores.into_iter().collect();
    results.sort_by(|a, b| {
        b.1.combined_score
            .partial_cmp(&a.1.combined_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    results.truncate(limit);
    results
}

fn lexical_rerank_score(
    chunk: &crate::types::ScoredCodeChunk,
    query_lower: &str,
    terms: &[String],
    codeish: bool,
) -> f32 {
    let path = chunk.file_path.to_lowercase();
    let name = chunk.name.clone().unwrap_or_default().to_lowercase();
    let ctx = chunk
        .context_path
        .clone()
        .unwrap_or_default()
        .to_lowercase();
    let content = chunk.content.to_lowercase();

    let mut raw = 0.0f32;
    let mut matched_terms = 0usize;
    let mut strong_hit = false;

    if query_lower.len() >= 4
        && (path.contains(query_lower) || name.contains(query_lower) || ctx.contains(query_lower))
    {
        raw += 1.8;
        strong_hit = true;
    }

    for term in terms {
        if term.len() < 2 {
            continue;
        }
        let in_name = !name.is_empty() && name.contains(term);
        let in_path = path.contains(term);
        let in_ctx = !ctx.is_empty() && ctx.contains(term);
        let in_content = content.contains(term);

        if in_name {
            raw += 0.7;
            matched_terms += 1;
            strong_hit = true;
        } else if in_path {
            raw += 0.55;
            matched_terms += 1;
            strong_hit = true;
        } else if in_ctx {
            raw += 0.45;
            matched_terms += 1;
        } else if in_content {
            raw += 0.2;
            matched_terms += 1;
        }
    }

    if !terms.is_empty() {
        raw += 0.8 * (matched_terms as f32 / terms.len() as f32);
    }

    if codeish && strong_hit {
        raw += 0.8;
    }

    // Penalize very short generic chunks unless they have strong lexical evidence.
    if chunk.content.len() < 96 && !strong_hit {
        raw -= 0.6;
    }

    raw.clamp(0.0, 4.0) / 4.0
}

